using System;
using System.Collections.Generic;
using System.Threading;

/// <summary>
/// Migrated from .NET Framework to .NET 8.
/// Replaced Thread.Interrupt/Thread.Abort with cooperative CancellationToken.
/// Replaced ManualResetEvent with ManualResetEventSlim for better performance.
/// </summary>
public class EventProcessor : IDisposable
{
    private readonly ManualResetEventSlim _newEvent = new ManualResetEventSlim(false);
    private readonly Queue<string> _queue = new Queue<string>();
    private readonly CancellationTokenSource _cts = new CancellationTokenSource();
    private Thread? _thread;
    private readonly object _lock = new object();

    public void Start()
    {
        _thread = new Thread(RunLoop);
        _thread.Start();
    }

    private void RunLoop()
    {
        var token = _cts.Token;

        while (!token.IsCancellationRequested)
        {
            try
            {
                // WaitAny wakes on either a new event OR cancellation
                WaitHandle.WaitAny(new[] { _newEvent.WaitHandle, token.WaitHandle });

                if (token.IsCancellationRequested)
                    break;

                _newEvent.Reset();

                string? item = null;
                lock (_lock)
                {
                    if (_queue.Count > 0)
                        item = _queue.Dequeue();
                }

                if (item != null)
                    Handle(item);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public void Enqueue(string item)
    {
        lock (_lock) { _queue.Enqueue(item); }
        _newEvent.Set();
    }

    public void Stop()
    {
        _cts.Cancel();            // signals the token — wakes WaitAny
        _thread?.Join(5000);      // wait up to 5 s for graceful exit
        // No Thread.Abort fallback — cooperative cancellation is sufficient
    }

    public void Dispose()
    {
        Stop();
        _cts.Dispose();
        _newEvent.Dispose();
    }

    private void Handle(string item)
    {
        // processing logic here
    }
}

